<template><view class="page"><xy-header title="邀请好友"/><view class="card"><text>我的邀请码</text><text class="code">{{inviteCode||'------'}}</text><button @click="copy">复制邀请码</button><button open-type="share">分享给好友</button></view></view></template>
<script>import{appRequest,ensureMemberSession,showRequestError}from'../../utils/api';export default{data(){return{inviteCode:''}},onLoad(){this.load()},onShareAppMessage(){return{title:`邀请你加入钓虾，邀请码 ${this.inviteCode}`,path:`/pages/index/index?inviteCode=${this.inviteCode}`}},methods:{async load(){try{await ensureMemberSession();const me=await appRequest({url:'/app/me'});this.inviteCode=me.inviteCode}catch(e){showRequestError(e)}},copy(){uni.setClipboardData({data:this.inviteCode})}}}</script><style scoped>.page{min-height:100vh;padding:70rpx 30rpx;background:var(--xy-bg)}.card{display:flex;flex-direction:column;align-items:center;gap:28rpx;padding:60rpx;border-radius:28rpx;background:#fff}.code{font-size:64rpx;font-weight:800;letter-spacing:10rpx;color:var(--xy-primary)}button{width:100%}</style>
